from flask import Flask

app = Flask(__name__)

@app.template_filter('pluralize')
def pluralize_filter(count, word):
    if count == 1:
        return f'{count} {word}'
    return f'{count} {word}s'

# Usage in template: {{ items|length|pluralize('item') }}

